def _sap_erp_column_to_nested(sap_erp_column: SapErpColumn) -> SapErpColumnNested:
    """Convert flat SapErpColumn to nested format."""
    attrs = SapErpColumnAttributes()
    _populate_sap_erp_column_attrs(attrs, sap_erp_column)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        sap_erp_column, _SAP_ERP_COLUMN_REL_FIELDS, SapErpColumnRelationshipAttributes
    )
    return SapErpColumnNested(
        guid=sap_erp_column.guid,
        type_name=sap_erp_column.type_name,
        status=sap_erp_column.status,
        version=sap_erp_column.version,
        create_time=sap_erp_column.create_time,
        update_time=sap_erp_column.update_time,
        created_by=sap_erp_column.created_by,
        updated_by=sap_erp_column.updated_by,
        classifications=sap_erp_column.classifications,
        classification_names=sap_erp_column.classification_names,
        meanings=sap_erp_column.meanings,
        labels=sap_erp_column.labels,
        business_attributes=sap_erp_column.business_attributes,
        custom_attributes=sap_erp_column.custom_attributes,
        pending_tasks=sap_erp_column.pending_tasks,
        proxy=sap_erp_column.proxy,
        is_incomplete=sap_erp_column.is_incomplete,
        provenance_type=sap_erp_column.provenance_type,
        home_id=sap_erp_column.home_id,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _sap_erp_column_from_nested(nested: SapErpColumnNested) -> SapErpColumn:
    """Convert nested format to flat SapErpColumn."""
    attrs = (
        nested.attributes
        if nested.attributes is not UNSET
        else SapErpColumnAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _SAP_ERP_COLUMN_REL_FIELDS,
        SapErpColumnRelationshipAttributes,
    )
    return SapErpColumn(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        meanings=nested.meanings,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        **_extract_sap_erp_column_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _sap_erp_column_to_nested_bytes(
    sap_erp_column: SapErpColumn, serde: Serde
) -> bytes:
    """Convert flat SapErpColumn to nested JSON bytes."""
    return serde.encode(_sap_erp_column_to_nested(sap_erp_column))


def _sap_erp_column_from_nested_bytes(data: bytes, serde: Serde) -> SapErpColumn:
    """Convert nested JSON bytes to flat SapErpColumn."""
    nested = serde.decode(data, SapErpColumnNested)
    return _sap_erp_column_from_nested(nested)


